import{_ as a,o as i,c as t,a0 as o}from"./chunks/framework.jwovEGr5.js";const u=JSON.parse('{"title":"Set Up Your Gemini API Key","description":"","frontmatter":{},"headers":[],"relativePath":"imports/gemini-key.md","filePath":"imports/gemini-key.md"}'),r={name:"imports/gemini-key.md"};function l(s,e,n,h,c,d){return i(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="set-up-your-gemini-api-key" tabindex="-1">Set Up Your Gemini API Key <a class="header-anchor" href="#set-up-your-gemini-api-key" aria-label="Permalink to &quot;Set Up Your Gemini API Key&quot;">​</a></h1><p>Gemini can improve screenshot reading quality, but it needs an API key.</p><blockquote><p>Screenshot placeholder: ocr-gemini-key.png</p></blockquote><h2 id="the-privacy-detail-that-matters" tabindex="-1">The privacy detail that matters <a class="header-anchor" href="#the-privacy-detail-that-matters" aria-label="Permalink to &quot;The privacy detail that matters&quot;">​</a></h2><p>Your Gemini key is stored <strong>in this browser</strong>, not on the server.</p><p>That means:</p><ul><li>it stays local to the browser you saved it in</li><li>another browser or device will not automatically have it</li><li>clearing local browser data can remove it</li></ul><h2 id="basic-steps" tabindex="-1">Basic steps <a class="header-anchor" href="#basic-steps" aria-label="Permalink to &quot;Basic steps&quot;">​</a></h2><ol><li>Open <strong>Image Processing Settings</strong>.</li><li>Choose <strong>Gemini</strong>.</li><li>Paste your API key.</li><li>Confirm or change the model.</li><li>Select <strong>Test connection</strong>.</li><li>Select <strong>Save locally</strong>.</li></ol><p>The page shows whether your browser key is saved and whether a global key also exists.</p><h2 id="when-to-use-a-browser-key" tabindex="-1">When to use a browser key <a class="header-anchor" href="#when-to-use-a-browser-key" aria-label="Permalink to &quot;When to use a browser key&quot;">​</a></h2><p>Use your own browser key when:</p><ul><li>you want Gemini quality right now</li><li>the platform is not using a shared global key for your workflow</li><li>you are working on a device you control</li></ul><h2 id="if-gemini-still-looks-unavailable" tabindex="-1">If Gemini still looks unavailable <a class="header-anchor" href="#if-gemini-still-looks-unavailable" aria-label="Permalink to &quot;If Gemini still looks unavailable&quot;">​</a></h2><p>Check these common reasons:</p><ul><li>Gemini is disabled by admin</li><li>the key was not saved in this browser</li><li>the key or model test failed</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./choose-provider.html">Choose an Image-Processing Provider</a></li><li><a href="./../admin/ocr-settings.html">Administer OCR Providers</a></li></ul>',18)])])}const p=a(r,[["render",l]]);export{u as __pageData,p as default};
